/** 明显的非技术话题关键词 */
const OFF_TOPIC_PATTERNS = [
  /how\s+to\s+(hack|steal|exploit|break\sin|bypass\s+security)/i,
  /write\s+(malware|virus|ransomware|trojan)/i,
  /generate\s+(fake|false)\s+(news|information)/i,
