def is_binary(file_path: str) -> bool:
    """快速检测文件是否为二进制"""
    try:
        with open(file_path, "rb") as f:
            chunk = f.read(1024)
            # 检测 null 字节
            if b"\x00" in chunk:
                return True
    except OSError:
        return True
    return False


